noncompliant:
// Noncompliant: interface inherits from bases with colliding member
public interface IBase1
{
    void DoSomething();
}

public interface IBase2
{
    void DoSomething();
}

public interface IDerived : IBase1, IBase2  // Noncompliant
{
    // Inherits two DoSomething() methods - collision!
}

compliant:
// Compliant: derived interface provides new implementation to resolve collision
public interface IBase1
{
    void DoSomething();
}

public interface IBase2
{
    void DoSomething();
}

public interface IDerived : IBase1, IBase2
{
    new void DoSomething(); // Explicit new member resolves collision
}

// Compliant: no collision
public interface IBase1
{
    void DoSomething();
}

public interface IBase2
{
    void DoSomethingElse();
}

public interface IDerived : IBase1, IBase2
{
    // No collision - different method names
}
